import{_ as t,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Random Image API and Public Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/random-image-api-and-public-gallery.md","filePath":"en/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"en/Other/random-image-api-and-public-gallery.md"};function o(s,e,l,n,c,p){return a(),d("div",null,[...e[0]||(e[0]=[r(`<h1 id="random-image-api-and-public-gallery" tabindex="-1">Random Image API and Public Gallery <a class="header-anchor" href="#random-image-api-and-public-gallery" aria-label="Permalink to &quot;Random Image API and Public Gallery&quot;">​</a></h1><p>Both features are configured under:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>The Random Image API returns one random file from selected directories. It is useful for site backgrounds, avatar rotation, or random image calls from external pages.</p><p>After it is enabled, use:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="random-image-api-settings" tabindex="-1">Random Image API Settings <a class="header-anchor" href="#random-image-api-settings" aria-label="Permalink to &quot;Random Image API Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Turns the <code>/random</code> endpoint on or off. When disabled, access is forbidden.</td></tr><tr><td>Directories</td><td>Limits which directories the random API can use. Directories not included here cannot be used by the API.</td></tr><tr><td>Call demo</td><td>Generates random API links you can copy directly.</td></tr></tbody></table><p>You can select multiple directories. For example, if only <code>/landscape/</code> and <code>/portrait/</code> are allowed, the random API can only pick files from those directories and their subdirectories.</p><h2 id="random-image-api-parameters" tabindex="-1">Random Image API Parameters <a class="header-anchor" href="#random-image-api-parameters" aria-label="Permalink to &quot;Random Image API Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Example</th><th>Purpose</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Specifies the random directory.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Specifies media type. Use <code>image</code>, <code>video</code>, <code>audio</code>, or comma-separated combinations.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filters image orientation. Use <code>portrait</code>, <code>landscape</code>, or <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Return format. Empty means redirect, <code>url</code> returns plain text URL, <code>json</code> returns JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Used with <code>type=url</code> to return a full URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filters by age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Only returns files containing these tags.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Excludes files containing these tags.</td></tr></tbody></table><h2 id="return-formats" tabindex="-1">Return Formats <a class="header-anchor" href="#return-formats" aria-label="Permalink to &quot;Return Formats&quot;">​</a></h2><p>Without <code>type</code>, the API redirects directly to the random file URL.</p><p>With <code>type=url</code>, it returns a text URL.</p><p>With <code>type=json</code>, it returns file information, including file URL, file ID, file name, file type, tags, rating, and related metadata.</p><h2 id="access-rules" tabindex="-1">Access Rules <a class="header-anchor" href="#access-rules" aria-label="Permalink to &quot;Access Rules&quot;">​</a></h2><p>The Random Image API follows public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Only files in allowed directories can be selected.</td></tr><tr><td>Blocklist</td><td>Blocklisted files are excluded from the random pool.</td></tr><tr><td>Allowlist mode</td><td>When enabled, only files allowed for public access are returned.</td></tr><tr><td>Age rating</td><td>R12, R16, R18, and similar content is filtered by the current access mode.</td></tr></tbody></table><p>If no file matches after filtering, the API returns no matching result.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>The Random Image API caches directory candidate pools to improve speed.</p><p>After files change, ImgBed updates the directory cache version, and later requests rebuild the candidate pool. Empty directories are cached briefly to avoid repeated queries.</p><h2 id="public-gallery" tabindex="-1">Public Gallery <a class="header-anchor" href="#public-gallery" aria-label="Permalink to &quot;Public Gallery&quot;">​</a></h2><p>The public gallery provides a read-only public browsing page for directories you allow visitors to see.</p><p>After it is enabled, visitors can open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="public-gallery-settings" tabindex="-1">Public Gallery Settings <a class="header-anchor" href="#public-gallery-settings" aria-label="Permalink to &quot;Public Gallery Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Enable</td><td>Turns the public gallery on or off. When disabled, visitors cannot browse it.</td></tr><tr><td>Image loading mode</td><td>Controls whether previews use original images or thumbnails.</td></tr><tr><td>Open directories</td><td>Sets which directories visitors can access.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td>Original</td><td>The visitor page loads original files directly.</td></tr><tr><td>Thumbnail</td><td>The visitor page prefers thumbnails for faster loading.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories decide what visitors can see.</p><p>For example:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Visitors can then access:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Subdirectories can also be opened, such as <code>/2026/lucky/</code>. Visitors are blocked from directories that are not open.</p><h2 id="public-gallery-features" tabindex="-1">Public Gallery Features <a class="header-anchor" href="#public-gallery-features" aria-label="Permalink to &quot;Public Gallery Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Browse directories</td><td>View files and subdirectories in open directories.</td></tr><tr><td>Search</td><td>Search by file name, file ID, or tags.</td></tr><tr><td>Type filter</td><td>Filter images, videos, audio, or other files.</td></tr><tr><td>Tag filter</td><td>Include or exclude selected tags.</td></tr><tr><td>Orientation filter</td><td>Filter landscape or portrait images.</td></tr><tr><td>Time filter</td><td>Filter by upload time range.</td></tr><tr><td>Extension filter</td><td>Filter by file extension.</td></tr><tr><td>Copy link</td><td>Copy file access links.</td></tr><tr><td>Media preview</td><td>View or play images, videos, and audio on the visitor page.</td></tr></tbody></table><h2 id="public-gallery-access-rules" tabindex="-1">Public Gallery Access Rules <a class="header-anchor" href="#public-gallery-access-rules" aria-label="Permalink to &quot;Public Gallery Access Rules&quot;">​</a></h2><p>The public gallery also follows public access rules:</p><table tabindex="0"><thead><tr><th>Rule</th><th>Effect</th></tr></thead><tbody><tr><td>Open directories</td><td>Only allowed directories are shown.</td></tr><tr><td>Access mode</td><td>Content is filtered by the current age-rating access mode.</td></tr><tr><td>Allowlist mode</td><td>When enabled, only files allowed for public access are shown.</td></tr><tr><td>Blocklist</td><td>Blocklisted files are hidden.</td></tr></tbody></table>`,43)])])}const m=t(i,[["render",o]]);export{u as __pageData,m as default};
